# Simple Claude Integration for Next.js

Here's the most straightforward approach using the Anthropic SDK:

## 1. Install Dependencies

```bash
npm install @anthropic-ai/sdk
```

## 2. Create an API Route (app/api/chat/route.ts)

```typescript
import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();

export async function POST(request: Request) {
  const { messages, context } = await request.json();

  const stream = client.messages.stream({
    model: "claude-3-5-sonnet-20241022",
    max_tokens: 1024,
    system: `You are a helpful assistant analyzing user data. ${context || ""}`,
    messages: messages,
  });

  // Convert to ReadableStream for streaming response
  const encoder = new TextEncoder();
  const readable = new ReadableStream({
    async start(controller) {
      try {
        for await (const chunk of stream) {
          if (
            chunk.type === "content_block_delta" &&
            chunk.delta.type === "text_delta"
          ) {
            controller.enqueue(
              encoder.encode(chunk.delta.text)
            );
          }
        }
        controller.close();
      } catch (error) {
        controller.error(error);
      }
    },
  });

  return new Response(readable, {
    headers: {
      "Content-Type": "text/event-stream",
      "Cache-Control": "no-cache",
      Connection: "keep-alive",
    },
  });
}
```

## 3. Create a Client Component (components/ChatInterface.tsx)

```typescript
"use client";

import { useState, useRef, useEffect } from "react";

export function ChatInterface({ dataContext }: { dataContext: string }) {
  const [messages, setMessages] = useState<
    Array<{ role: "user" | "assistant"; content: string }>
  >([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || loading) return;

    // Add user message
    const userMessage = { role: "user" as const, content: input };
    setMessages((prev) => [...prev, userMessage]);
    setInput("");
    setLoading(true);

    try {
      const response = await fetch("/api/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          messages: [...messages, userMessage],
          context: dataContext,
        }),
      });

      if (!response.body) throw new Error("No response body");

      const reader = response.body.getReader();
      const decoder = new TextDecoder();
      let assistantMessage = "";

      // Stream in chunks
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const text = decoder.decode(value);
        assistantMessage += text;

        // Update UI with streaming text
        setMessages((prev) => {
          const updated = [...prev];
          if (
            updated[updated.length - 1]?.role === "assistant"
          ) {
            updated[updated.length - 1].content = assistantMessage;
          } else {
            updated.push({
              role: "assistant",
              content: assistantMessage,
            });
          }
          return updated;
        });
      }
    } catch (error) {
      console.error("Error:", error);
      setMessages((prev) => [
        ...prev,
        {
          role: "assistant",
          content: "Sorry, something went wrong.",
        },
      ]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-screen">
      <div className="flex-1 overflow-y-auto p-4">
        {messages.map((msg, i) => (
          <div
            key={i}
            className={`mb-4 ${
              msg.role === "user" ? "text-right" : "text-left"
            }`}
          >
            <div
              className={`inline-block max-w-md rounded-lg p-3 ${
                msg.role === "user"
                  ? "bg-blue-500 text-white"
                  : "bg-gray-200 text-black"
              }`}
            >
              {msg.content}
            </div>
          </div>
        ))}
      </div>

      <form onSubmit={handleSubmit} className="p-4 border-t">
        <div className="flex gap-2">
          <input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask a question..."
            className="flex-1 border rounded-lg px-4 py-2"
            disabled={loading}
          />
          <button
            type="submit"
            disabled={loading}
            className="bg-blue-500 text-white px-6 py-2 rounded-lg disabled:opacity-50"
          >
            {loading ? "..." : "Send"}
          </button>
        </div>
      </form>
    </div>
  );
}
```

## 4. Set Environment Variable

```bash
# .env.local
ANTHROPIC_API_KEY=your_key_here
```

## 5. Use in a Page

```typescript
import { ChatInterface } from "@/components/ChatInterface";

export default function DataPage() {
  // Fetch or generate context from user's data
  const dataContext = "User's quarterly sales data: Q1: $50k, Q2: $75k...";

  return <ChatInterface dataContext={dataContext} />;
}
```

## Key Features
- ✅ Real-time streaming responses
- ✅ Context-aware (inject user data into system prompt)
- ✅ Conversation history
- ✅ Simple error handling
- ✅ Minimal dependencies

## Optional: Use Vercel AI SDK
If you want even more abstraction:

```bash
npm install ai
```

The `ai` package handles streaming boilerplate, but the manual approach above gives you more control.

